            aOrbiterA = ((aWandererC + RotL64(aScatter, 10U)) + 0x179DCA05B8AE1B42ULL) + aPhaseBOrbiterAssignSaltF[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterE = (aWandererG + RotL64(aPrevious, 21U)) + 0x2BC8260B1F255E4DULL;
            aOrbiterJ = ((aWandererF + RotL64(aIngress, 35U)) + 0xC590118C4594366AULL) + aPhaseBOrbiterAssignSaltE[(((31U - aIndex) + 17U)) & S_SALT1];
