            aOrbiterG = (aOrbiterG + aOrbiterI) + 0x0F4A825B19EE6028ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 0xE7E0CCCDBE2C96E2ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x92DF14D962225D33ULL), 5U);
