            aOrbiterE = (aOrbiterE + aOrbiterD) + 0x48DD0108EAEFAAF0ULL;
            aOrbiterK = ((aOrbiterK ^ aOrbiterE) ^ 0x11217AA02248D4B0ULL) ^ aPhaseEOrbiterUpdateSaltF[((aIndex + 21U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 0xC60630DCB8C744D3ULL), 37U);
            //
            aIngress = aOrbiterD ^ RotL64(aOrbiterK, 39U);
