            aOrbiterC = RotL64((aOrbiterC * 0x912827631BABD3E5ULL), 57U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterC) + 0xED9C7CE301505F2FULL) + aPhaseFOrbiterUpdateSaltB[((aIndex + 7U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterJ) ^ 0xDAC6C17CA5F59825ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x4832D80A2E3E2635ULL), 53U);
