            aWandererE = aWandererE + ((RotL64(aPrevious, 57U) + RotL64(aOrbiterB, 57U)) + aOrbiterA);
            aWandererC = aWandererC ^ (((RotL64(aScatter, 6U) + RotL64(aOrbiterJ, 26U)) + aOrbiterA) + aPhaseEWandererUpdateSaltF[((aIndex + 6U)) & S_SALT1]);
            aWandererI = aWandererI + (((RotL64(aPrevious, 23U) + RotL64(aOrbiterE, 19U)) + aOrbiterA) + RotL64(aCarry, 19U));
            //
            aCarry = aCarry + (aWandererE ^ RotL64(aWandererB, 44U));
