            //
            aScatter = (RotL64(aPrevious, 20U) ^ RotL64(aCross, 37U)) ^ (RotL64(aIngress, 53U) + RotL64(aCarry, 5U));
            aScatter = TwistMix64::DiffuseB(aScatter);
            //
            aOrbiterJ = (aWandererA + RotL64(aPrevious, 19U)) + 0xA2BDA426BB0B2EB3ULL;
            aOrbiterI = (aWandererE + RotL64(aScatter, 27U)) + 0xDF063798438F2B15ULL;
