            aOrbiterH = (aWandererJ + RotL64(aPrevious, 21U)) + 0x5AF6F6976D32889DULL;
            aOrbiterB = (((aWandererD + RotL64(aCross, 51U)) + RotL64(aCarry, 3U)) + 0x6BACA65C8FC4D9CAULL) + aPhaseGOrbiterAssignSaltB[(((31U - aIndex) + 15U)) & S_SALT1];
            aOrbiterK = ((aWandererF + RotL64(aScatter, 58U)) + 0x7728ECA8F254CE64ULL) + aPhaseGOrbiterAssignSaltF[(((31U - aIndex) + 14U)) & S_SALT1];
