            aOrbiterA = RotL64((aOrbiterA * 0x79F3E7A681ED7A5BULL), 13U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterA) + 0xCA8682976EE09134ULL) + aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 0x929436EFC165F73CULL;
            aOrbiterH = RotL64((aOrbiterH * 0x0885E4D6C2F52F41ULL), 41U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 0x7A8E5CE9B39EF9C0ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterB) ^ 0x6EF63B6E629510CFULL;
            aOrbiterD = RotL64((aOrbiterD * 0xF5EB4CF1DA3C1E9DULL), 43U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0xCEE643C4138841B3ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterA) ^ 0x2793B7318879299AULL;
            aOrbiterG = RotL64((aOrbiterG * 0xDF93F27C549A9859ULL), 5U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0xFD5739FC4489EE65ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterG) ^ 0xB53A4F942589EE79ULL) ^ aPhaseGOrbiterUpdateSaltC[((aIndex + 4U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0xF08B836BF9F03EFBULL), 57U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 0x42C96AA37F721E9EULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 0xADB88893DC127D31ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x8B9795D4B673D329ULL), 53U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 0x5F859E43E0CB9603ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0xE95D982C546CBBAEULL;
            aOrbiterB = RotL64((aOrbiterB * 0xE1E333B5F5F193BBULL), 47U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 0x7A092FB2299E1F2AULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0x46F7A0F9BC0753B9ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x76139AA14AF8EF0DULL), 23U);
